    #[tokio::test]
    async fn explore_triage_skips_redundant_seeds() {
        let config = config_for_script("fixed-branch-frontend.sh");
        let mut frontend = Frontend::spawn(&config).await.expect("spawn failed");

        let explore_config = ExploreConfig {
            max_iterations: 50,
