    #[test]
    fn frontend_capabilities_ignores_unknown_complex_types() {
        let caps = FrontendCapabilities::from_raw(&[
            "complex_type:date".into(),
            "complex_type:nonexistent_type".into(),
            "complex_type:".into(),
