    #[test]
    fn frontend_capabilities_separates_commands_from_complex_types() {
        let caps = FrontendCapabilities::from_raw(&[
            "analyze".into(),
            "execute".into(),
            "instrument".into(),
            "complex_type:date".into(),
            "complex_type:url".into(),
        ]);
        assert_eq!(caps.commands.len(), 3);
