    #[test]
    fn frontend_capabilities_default_is_empty() {
        let caps = FrontendCapabilities::default();
        assert!(caps.commands.is_empty());
        assert!(caps.complex_types.is_empty());
        assert!(!caps.supports_complex(ComplexKind::Date));
