        let mut frontend = Frontend::spawn(&config).await.expect("spawn failed");

        let explore_config = ExploreConfig {
            max_iterations: 100,
            max_executions: 100,
            // Low threshold so plateau triggers quickly.
            plateau_threshold: 3,
            ..Default::default()
        };

