    #[test]
    fn frontend_capabilities_parses_complex_types() {
        let caps = FrontendCapabilities::from_raw(&[
            "analyze".into(),
            "execute".into(),
            "complex_type:date".into(),
            "complex_type:reg_exp".into(),
            "complex_type:big_int".into(),
