        seen.insert(42u64);
        seen.insert(99u64);

        let mut ctx = FitnessContext::from_seen_paths(seen);
        assert!(!ctx.mark_seen(42), "pre-seeded path should not be novel");
        assert!(ctx.mark_seen(100), "unseen path should be novel");
    }

