    /// No new paths discovered for `plateau_threshold` consecutive executions.
    CoveragePlateau,
    /// The worklist is empty — all reachable paths have been explored.
    WorklistExhausted,
    /// Exceeded the per-function exploration wall-clock timeout.
    TimeoutExplore,
}

