        // Should produce: 6, 4, 0, -5 = 4 mutations
        assert_eq!(fuzzed.len(), 4);
        assert!(fuzzed.contains(&vec![serde_json::json!(6)]));
        assert!(fuzzed.contains(&vec![serde_json::json!(4)]));
