    fn fuzz_zero_produces_mutations() {
        let inputs = vec![serde_json::json!(0)];
        let fuzzed = fuzz_inputs(&inputs);
        // Candidates: 1, -1, 0, 0. Skip 0 (== original), dedup → 1, -1
        assert_eq!(fuzzed.len(), 2);
