    fn fuzz_boolean_flips() {
        let inputs = vec![serde_json::json!(true)];
        let fuzzed = fuzz_inputs(&inputs);
        assert_eq!(fuzzed.len(), 1);
        assert_eq!(fuzzed[0], vec![serde_json::json!(false)]);
