            unique_paths: 2,
            lines_covered: 5,
            total_lines: 10,
            new_path_executions: vec![
                ExecutionSummary {
                    inputs: vec![json!(5)],
                    return_value: Some(json!("positive")),
                    thrown_error: None,
                    lines_executed: vec![1, 2],
                    is_new_path: true, error_intent: None },
                ExecutionSummary {
                    inputs: vec![json!(-1)],
