fn load_returns_none_for_missing() {
    let dir = tempfile::tempdir().unwrap();
    let cache = BehaviorMapCache::new(dir.path().to_path_buf()).unwrap();

    let result = cache.load("nonexistent").unwrap();
    assert_eq!(result, None);
}

